import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import Captcha from "../../components/Captcha";

const roles = [
  { value: "admin", label: "Admin" },
  { value: "instructor", label: "Instructor" },
  { value: "student", label: "Student" },
  { value: "content", label: "Content Creator" },
];

function Login() {
  const navigate = useNavigate();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("");
  const [captchaInput, setCaptchaInput] = useState("");
  const [captchaCode, setCaptchaCode] = useState("");
  const [error, setError] = useState("");

  const handleLogin = () => {
    if (!email || !password || !role || !captchaInput) {
      setError("All fields are required");
      return;
    }
    if (captchaInput.toUpperCase() !== captchaCode) {
      setError("Captcha is incorrect");
      return;
    }
    setError("");

    // Save role in localStorage to simulate session
    localStorage.setItem("role", role);

    // Redirect to dashboard based on selected role
    switch (role) {
      case "admin":
        navigate("/admin");
        break;
      case "instructor":
        navigate("/instructor");
        break;
      case "student":
        navigate("/student");
        break;
      case "content":
        navigate("/content");
        break;
      default:
        navigate("/");
    }
  };

  return (
    <div className="container d-flex justify-content-center align-items-center vh-100">
      <div className="card p-4 shadow" style={{ width: "400px" }}>
        <h3 className="text-center mb-4">NexaLearn LMS</h3>
        {error && <div className="alert alert-danger">{error}</div>}

        <input
          type="email"
          className="form-control mb-3"
          placeholder="Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />

        <input
          type="password"
          className="form-control mb-3"
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />

        <select
          className="form-select mb-3"
          value={role}
          onChange={(e) => setRole(e.target.value)}
        >
          <option value="">Select Role</option>
          {roles.map((r) => (
            <option key={r.value} value={r.value}>
              {r.label}
            </option>
          ))}
        </select>

        <Captcha onChange={setCaptchaCode} />

        <input
          type="text"
          className="form-control mb-3 mt-2"
          placeholder="Enter verification code"
          value={captchaInput}
          onChange={(e) => setCaptchaInput(e.target.value)}
        />

        <button className="btn btn-primary w-100" onClick={handleLogin}>
          Login
        </button>

        <p className="mt-3 text-center">
          Don't have an account? <a href="/register">Register</a>
        </p>
      </div>
    </div>
  );
}

export default Login;
